 1	import { type FC, type Ref, useState } from 'react';
 2	import { useNavigate } from 'react-router-dom-v5-compat';
 3	import { getResourceUrl } from 'src/modules/Providers/utils/helpers/getResourceUrl';
 4	import { useForkliftTranslation } from 'src/utils/i18n';
 5	
 6	import { NetworkMapModelRef } from '@kubev2v/types';
 7	import {
 8	  ButtonVariant,
 9	  Dropdown,
10	  DropdownItem,
11	  DropdownList,
12	  MenuToggle,
13	  type MenuToggleElement,
14	} from '@patternfly/react-core';
15	import { CreationMethod, TELEMETRY_EVENTS } from '@utils/analytics/constants';
16	import { useForkliftAnalytics } from '@utils/analytics/hooks/useForkliftAnalytics';
17	
18	const NetworkMapsAddButton: FC<{ namespace?: string; testId?: string }> = ({
19	  namespace,
20	  testId,
21	}) => {
22	  const { t } = useForkliftTranslation();
23	  const navigate = useNavigate();
24	  const { trackEvent } = useForkliftAnalytics();
25	  const [isMenuOpen, setIsMenuOpen] = useState(false);
26	
27	  const networkMapsListUrl = getResourceUrl({
28	    namespace,
29	    namespaced: namespace !== undefined,
30	    reference: NetworkMapModelRef,
31	  });
32	
33	  return (
34	    <Dropdown
35	      isOpen={isMenuOpen}
36	      onOpenChange={(isOpen: boolean) => {
37	        setIsMenuOpen(isOpen);
38	      }}
39	      data-testid={testId}
40	      toggle={(toggleRef: Ref<MenuToggleElement>) => (
41	        <MenuToggle
42	          ref={toggleRef}
43	          onClick={() => {
44	            setIsMenuOpen(!isMenuOpen);
45	          }}
46	          isExpanded={isMenuOpen}
47	          variant={ButtonVariant.primary}
48	        >
49	          {t('Create network map')}
50	        </MenuToggle>
51	      )}
52	      shouldFocusFirstItemOnOpen={false}
53	      popperProps={{
54	        position: 'right',
55	      }}
56	    >
57	      <DropdownList>
58	        <DropdownItem
59	          key="form"
60	          data-testid="create-network-map-dropdown-item-form"
61	          onClick={() => {
62	            trackEvent(TELEMETRY_EVENTS.NETWORK_MAP_CREATE_STARTED, {
63	              creationMethod: CreationMethod.Form,
64	              namespace,
65	            });
66	            navigate(`/k8s/networkMaps/create/form`);
67	          }}
68	        >
69	          {t('Create with form')}
70	        </DropdownItem>
71	
72	        <DropdownItem
73	          key="yaml"
74	          data-testid="create-network-map-dropdown-item-yaml"
75	          onClick={() => {
76	            trackEvent(TELEMETRY_EVENTS.NETWORK_MAP_CREATE_STARTED, {
77	              creationMethod: CreationMethod.YamlEditor,
78	              namespace,
79	            });
80	            navigate(`${networkMapsListUrl}/~new`);
81	          }}
82	        >
83	          {t('Create with YAML')}
84	        </DropdownItem>
85	      </DropdownList>
86	    </Dropdown>
87	  );
88	};
89	
90	export default NetworkMapsAddButton;

